type DSU struct {
	parent []int
	// parity[i] stores the parity of the path weight from node i to its set representative (parent[i]).
	// 0 means even path weight, 1 means odd path weight.
	parity []int
}

// NewDSU initializes the DSU structure for n nodes.
func NewDSU(n int) *DSU {
	parent := make([]int, n)
	parity := make([]int, n)
	for i := 0; i < n; i++ {
		parent[i] = i
		parity[i] = 0 // Initially, path from i to i has weight 0 (even)
	}
	return &DSU{parent: parent, parity: parity}
}

// Find returns the representative of the set containing i, and the parity of the path
// from i to the representative. Uses path compression and updates parity.
func (d *DSU) Find(i int) (root int, pathParity int) {
	if d.parent[i] == i {
		return i, 0
	}

	// Recursively find the root and the parity from the parent to the root
	root, rootParity := d.Find(d.parent[i])

	// Path compression: set i's parent directly to the root
	d.parent[i] = root

	// Update parity for i: new_parity(i -> root) = parity(i -> old_parent) XOR parity(old_parent -> root)
	d.parity[i] = d.parity[i] ^ rootParity
	return root, d.parity[i]
}

// Union attempts to unite the sets containing u and v, considering the edge weight w.
// It returns true if the union was performed (i.e., u and v were in different sets),
// false if they were already connected (forming a cycle).
//
// When adding edge (u, v) with weight w:
// 1. Find representatives and path parities:
//    (root_u, parity_u) = Find(u)  -> path_u: u -> root_u
//    (root_v, parity_v) = Find(v)  -> path_v: v -> root_v
// 2. If root_u != root_v:
//    Merge the sets (e.g., set root_v to point to root_u).
//    We need to set the new parity for root_v -> root_u.
//    The path is: root_v --(path_v)--> v --(w)--> u --(path_u)--> root_u
//    The required parity for root_v -> root_u is: parity_v ^ w ^ parity_u
// 3. If root_u == root_v:
//    A cycle is formed. The cycle weight parity is:
//    CycleParity = path_u ^ w ^ path_v (since paths meet at the root)
//    If CycleParity is 1 (odd), the edge must be rejected.
func (d *DSU) Union(u, v int, w int) bool {
	rootU, parityU := d.Find(u)
	rootV, parityV := d.Find(v)

	if rootU != rootV {
		// Different components, add the edge.
		// Merge V's set into U's set (arbitrarily).
		d.parent[rootV] = rootU

		// Calculate the parity of the path from rootV to rootU.
		// Path: rootV --(pathV_reversed)--> v --(w)--> u --(pathU)--> rootU
		// parityV is v->rootV. Reversed: rootV->v has parityV.
		// Path: rootV -> v (parityV) -> u (w) -> rootU (parityU)
		// The weight of the path from rootV to rootU is: parityV ^ w ^ parityU
		// Note: parityV is the parity from V to rootV. Since DSU structure handles path compression,
		// the effective parity for rootV -> V is parityV.
		// We are setting parent[rootV] = rootU. We need parity[rootV] = weight(rootV -> rootU).
		// weight(rootV -> rootU) = weight(rootV -> V) + w + weight(u -> rootU)
		// weight(rootV -> V) = parityV (since parityV is V->rootV, and it's an undirected graph, this is fine).
		// weight(u -> rootU) = parityU
		d.parity[rootV] = parityV ^ w ^ parityU
		return true
	} else {
		// Same component, forms a cycle. Check the cycle parity.
		// Cycle path: u --(w)--> v --(path_v_reversed)--> rootU --(path_u)--> u
		// Parity = w ^ parityU ^ parityV
		cycleParity := w ^ parityU ^ parityV

		// The rule is: add the edge only if the resulting cycle parity is EVEN (0).
		if cycleParity == 0 {
			// Even cycle, allowed. Since they are in the same set, no structural change happens,
			// but the edge is conceptually added to the graph structure that satisfies the property.
			// However, since the problem asks for the count of *successfully added* edges, 
			// and adding an edge between two nodes already in the same set only forms a cycle,
			// we only count it if the cycle condition is met AND we are allowed to add it.
			// Since the condition is met (cycle parity is 0), we count it.
			return true 
		} else {
			// Odd cycle, not allowed.
			return false
		}
	}
}

func solve(n int64, edges [][]int64) int64 {
	N := int(n)
	dsu := NewDSU(N)
	addedEdgesCount := 0

	for _, edge := range edges {
		u := int(edge[0])
		v := int(edge[1])
		w := int(edge[2])

		// Check if adding the edge maintains the property (all cycles remain even weight)
		// The Union function returns true if the edge is added (either forming a new component or forming an even cycle).
		if dsu.Union(u, v, w) {
			addedEdgesCount++
		}
	}

	return int64(addedEdgesCount)
}
