func NewDSU(n int) *DSU {
	parent := make([]int, n)
	diff := make([]int, n)
	for i := 0; i < n; i++ {
		parent[i] = i
		diff[i] = 0
	}
	return &DSU{
		parent: parent,
		diff:   diff,
		count:  n,
	}
}

// Find returns the representative (root) of the set containing i,
// and updates the path compression and diff values along the way.
// It returns (root, parity_from_i_to_root).
func (d *DSU) Find(i int) (int, int) {
	if d.parent[i] == i {
		// i is the root, parity to itself is 0.
		return i, 0
	}
	// Recursively find the root and the parity from parent[i] to root.
	root, parityToRoot := d.Find(d.parent[i])

	// Path compression: set parent[i] directly to root.
	d.parent[i] = root

	// Update diff[i]:
	// The new path from i to root is: i -> parent[i] -> root.
	// The total parity is (i -> parent[i]) XOR (parent[i] -> root).
	// Original diff[i] is (i -> parent[i]).
	d.diff[i] = d.diff[i] ^ parityToRoot

	return root, d.diff[i]
}

// Union attempts to merge the sets containing u and v using the edge weight w.
// It returns true if the edge is added (i.e., it doesn't create a forbidden odd cycle),
// and false otherwise.
func (d *DSU) Union(u, v, w int) bool {
	rootU, parityU := d.Find(u)
	rootV, parityV := d.Find(v)

	if rootU != rootV {
		// Case 1: u and v are in different components.
		// Adding the edge (u, v) with weight w connects the two components.
		// This cannot form a cycle, so the condition about existing cycles is trivially met.
		// We merge V's set into U's set.
		d.parent[rootV] = rootU
		d.count--

		// We need to set diff[rootV] such that the path from rootV to rootU
		// (which is now parent[rootV]) has the correct parity.
		// Path: rootV --(path_V)--> v --(w)--> u --(path_U)--> rootU
		// We want: parity(rootV -> rootU)
		// We know:
		// 1. parity(v -> rootV) = parityV (or parityV from Find(v))
		// 2. parity(u -> rootU) = parityU
		// 3. parity(u -> v) = w
		//
		// We are setting parent[rootV] = rootU. We need diff[rootV] = parity(rootV -> rootU).
		// parity(rootV -> rootU) = parity(rootV -> v) XOR parity(v -> u) XOR parity(u -> rootU)
		// parity(rootV -> v) = parity(v -> rootV) = parityV
		// parity(v -> u) = w
		// parity(u -> rootU) = parityU
		//
		// Therefore, diff[rootV] = parityV ^ w ^ parityU
		d.diff[rootV] = parityV ^ w ^ parityU
		return true
	} else {
		// Case 2: u and v are already in the same component (forming a cycle).
		// The existing path between u and v has parity P_existing.
		// P_existing = parity(u -> root) XOR parity(v -> root)
		// Since parity(x -> root) = parity(root -> x) XOR 0, we have:
		// P_existing = parityU XOR parityV (because both parities are measured to rootU=rootV)

		// The new cycle is formed by path(u->v) + edge(v->u) with weight w.
		// Parity of the cycle = P_existing XOR w.
		// P_existing = parityU ^ parityV
		// Cycle Parity = (parityU ^ parityV) ^ w

		// The rule is: the cycle must have an even weight, meaning Cycle Parity must be 0.
		// (parityU ^ parityV) ^ w == 0  <==>  w == parityU ^ parityV
		// If this condition holds, the cycle is even, and we add the edge.
		// If this condition fails, the cycle is odd, and we reject the edge.

		if (parityU ^ parityV) == w {
			// Cycle is even. Add edge.
			return true
		} else {
			// Cycle is odd. Do not add edge.
			return false
		}
	}
}

