	for i := 0; i < n; i++ {
		parent[i] = i
		parity[i] = 0
	}
	return &UnionFind{
		parent: parent,
		parity: parity,
	}
}

// Find operation with path compression and parity update
// Returns the representative of i, and the parity of the path from i to the representative.
func (uf *UnionFind) Find(i int) (int, int) {
	if uf.parent[i] == i {
		return i, 0
	}
	// Recursively find the root and the parity from parent[i] to root
	root, parityToRoot := uf.Find(uf.parent[i])

	// Path compression: point i directly to the root
	uf.parent[i] = root

	// Update parity: The new parity from i to root is (old parity i->parent) XOR (parity parent->root)
	uf.parity[i] = uf.parity[i] ^ parityToRoot

	return root, uf.parity[i]
}

// Union operation
// Tries to unite the sets containing u and v with edge weight w.
// Returns true if the union was performed (i.e., u and v were in different components),
// and false if adding the edge creates a cycle.
// The condition for adding the edge is that it must maintain the property that all cycles have even weight sum.
func (uf *UnionFind) Union(u, v, w int) (bool, bool) {
	rootU, parityU := uf.Find(u)
	rootV, parityV := uf.Find(v)

	if rootU != rootV {
		// Case 1: u and v are in different components. Add the edge.
		// We merge V's set into U's set (arbitrarily).
		uf.parent[rootV] = rootU

		// We need to set parity[rootV] such that the path from rootV to rootU
		// has the correct XOR sum.
		// Path: rootV -> ... -> v --w-- u -> ... -> rootU
		// We know:
		// 1. Path from u to rootU has parity parityU. (i.e., dist(u, rootU) = parityU)
		// 2. Path from v to rootV has parity parityV. (i.e., dist(v, rootV) = parityV)
		// 3. Edge weight is w.
		// 
		// We want the parity of the path from rootV to rootU.
		// dist(rootV, rootU) = dist(rootV, v) + w + dist(u, rootU)
		// Since parity represents distance (XOR sum):
		// dist(rootV, v) = dist(v, rootV) = parityV
		// dist(u, rootU) = parityU
		// dist(rootV, rootU) = parityV ^ w ^ parityU

		uf.parity[rootV] = parityV ^ w ^ parityU
		return true, false // Successful addition, no cycle formed
